from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class PdfFieldCollection(PdfCollection):
    """
    Represents collection of the Pdf fields.
    """

    @dispatch
    def get_Item(self, index: int) -> PdfField:
        """
        Gets the field at the specified index.
        """

        GetDllLibPdf().spr_pdf_PdfFieldCollection_get_Item.argtypes = [c_void_p, c_int]
        GetDllLibPdf().spr_pdf_PdfFieldCollection_get_Item.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_get_Item,self.Ptr, index)
        ret = None if intPtr == None else PdfField(intPtr)
        return ret

    @dispatch
    def get_Item(self, name: str) -> PdfField:
        """
        Gets the field with their field name.
        """

        GetDllLibPdf().spr_pdf_PdfFieldCollection_get_ItemN.argtypes = [c_void_p, c_wchar_p]
        GetDllLibPdf().spr_pdf_PdfFieldCollection_get_ItemN.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_get_ItemN,self.Ptr, name)
        ret = None if intPtr == None else PdfField(intPtr)
        return ret

    def Add(self, field: 'PdfField') -> int:
        """
        Adds the specified field.
        Args: field: The field item which is added in the PDF form.
        Returns: The field to be added on the page.
        """
        intPtrfield: c_void_p = field.Ptr

        GetDllLibPdf().spr_pdf_PdfFieldCollection_Add.argtypes = [c_void_p, c_void_p]
        GetDllLibPdf().spr_pdf_PdfFieldCollection_Add.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_Add,self.Ptr, intPtrfield)
        return ret

    def Insert(self, index: int, field: 'PdfField'):
        """
        Inserts the field at the specified index.
        Args: index: The index of the field.
        Args: field: The field which should be inserted at the specified index.
        """
        intPtrfield: c_void_p = field.Ptr

        GetDllLibPdf().spr_pdf_PdfFieldCollection_Insert.argtypes = [c_void_p, c_int, c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_Insert,self.Ptr, index, intPtrfield)

    def Contains(self, field: 'PdfField') -> bool:
        """
        Determines whether field is contained within the collection.
        Args: field: Check whether object is present in the field collection or not.
        Returns: True if field is present in the collection, otherwise, False.
        """
        intPtrfield: c_void_p = field.Ptr

        GetDllLibPdf().spr_pdf_PdfFieldCollection_Contains.argtypes = [c_void_p, c_void_p]
        GetDllLibPdf().spr_pdf_PdfFieldCollection_Contains.restype = c_bool
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_Contains,self.Ptr, intPtrfield)
        return ret

    def IndexOf(self, field: 'PdfField') -> int:
        """
        Gets the index of the field.
        Args: field: The object whose index is requested.
        Returns: Index of the field in collection.
        """
        intPtrfield: c_void_p = field.Ptr

        GetDllLibPdf().spr_pdf_PdfFieldCollection_IndexOf.argtypes = [c_void_p, c_void_p]
        GetDllLibPdf().spr_pdf_PdfFieldCollection_IndexOf.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_IndexOf,self.Ptr, intPtrfield)
        return ret

    def Remove(self, field: 'PdfField'):
        """
        Removes the specified field in the collection.
        Args: field: The object to be removed from collection.
        """
        intPtrfield: c_void_p = field.Ptr

        GetDllLibPdf().spr_pdf_PdfFieldCollection_Remove.argtypes = [c_void_p, c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_Remove,self.Ptr, intPtrfield)

    def RemoveAt(self, index: int):
        """
        Removes field at the specified position.
        Args: index: The index where to remove the item.
        """
        GetDllLibPdf().spr_pdf_PdfFieldCollection_RemoveAt.argtypes = [c_void_p, c_int]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_RemoveAt,self.Ptr, index)

    def Clear(self):
        """
        Clears the form field collection.
        """
        GetDllLibPdf().spr_pdf_PdfFieldCollection_Clear.argtypes = [c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFieldCollection_Clear,self.Ptr)